// Merge: curated takes priority, auto-gen as fallback
const merged = { ...autoGen, ...curated };

// Test the key words
const testWords = ['panas','air','rumah','makan','baik','besar','kecil','sayang','bahagia','cantik','orang','anak','saya','kamu','dia','kita','mereka','ini','itu','apa','siapa','sudah','belum','sedang','akan','boleh','tidak','bukan','jangan','tahu','faham','dengar','lihat','jalan','duduk','tidur','bangun','minum','pakai','bawa','ambil','beri','tolong','panggil','tulis','baca','cakap','tanya','jawab','belajar','ajar','kerja','main','lari','masak','goreng','rebus','potong','buruk','tinggi','rendah','panjang','pendek','terima kasih','selamat pagi'];

let pass = 0, fail = 0;
for (const w of testWords) {
  const v = merged[w] || merged[w.toLowerCase()] || "(not found)";
  const isFound = v !== "(not found)";
  if (isFound) pass++; else fail++;
  const flag = isFound ? "✓" : "✗";
  console.log(flag + " " + w + " => " + v);
}
console.log("\nPassed:", pass + "/" + testWords.length);

writeFileSync('./malay-english-dict.json', JSON.stringify(merged));
console.log("Written to malay-english-dict.json (" + Object.keys(merged).length + " entries)");
